solution:
fn main() {
    let my_fav_fruits = vec!["banana", "custard apple", "avocado", "peach", "raspberry"];

    let mut fruit_iter = my_fav_fruits.iter();

    let first = fruit_iter.next();
    assert_eq!(first, Some(&"banana"));

    let second = fruit_iter.next();
    assert_eq!(second, Some(&"custard apple"));

    let third = fruit_iter.next();
    assert_eq!(third, Some(&"avocado"));

    println!("Done iterating!");
}
